DROP TABLE US_mapping;

CREATE TABLE US_mapping (
    State	VARCHAR2(512) PRIMARY KEY,
    Integration_scores	INT,
    SVD	FLOAT(50),
    VBAC	FLOAT(50),
    CS	FLOAT(50),
    Neodeath_all	FLOAT(50),
    Neodeath_Hispanic	VARCHAR(512),
    Neodeath_White	FLOAT(50),
    Neodeath_Honhispanic_Black	FLOAT(50),
    Preterm	FLOAT(50),
    LBW	FLOAT(50),
    Induction	FLOAT(50),
    Breastfeeding_at_6months	FLOAT(50),
    Breastfeeding_at_birth	FLOAT(50),
    Percent_black_births	FLOAT(50),
    CPM_Licensure	VARCHAR(512),
    CM_Licensure	VARCHAR(512),
    All_midwives_home_birthing_center_ACCESS	FLOAT(50),
    All_midwives_hospital_births_ACCESS	FLOAT(50),
    All_midwives_all_locations_ACCESS	FLOAT(50),
    CNM_CM_per_1000_births_DENSITY	FLOAT(50),
    CPM_per_1000_births_DENSITY	FLOAT(50),
    All_types_midwives_DENSITY	FLOAT(50),
    Homebirth_rate_2004	FLOAT(50),
    Homebirth_rate_2012	FLOAT(50),
    Change_homebirth_rate_2004_to_2012	FLOAT(50)
);

